class Solution:
    def minDays(self, grid):
        m, n = len(grid), len(grid[0])

        def count_islands(g):
            parent = list(range(m * n))

            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x

            def union(a, b):
                ra, rb = find(a), find(b)
                if ra != rb:
                    parent[ra] = rb

            for i in range(m):
                for j in range(n):
                    if g[i][j] == 1:
                        if i + 1 < m and g[i + 1][j] == 1:
                            union(i * n + j, (i + 1) * n + j)
                        if j + 1 < n and g[i][j + 1] == 1:
                            union(i * n + j, i * n + j + 1)
            roots = set()
            for i in range(m):
                for j in range(n):
                    if g[i][j] == 1:
                        roots.add(find(i * n + j))
            return len(roots)

        g = [row[:] for row in grid]
        if count_islands(g) != 1:
            return 0
        for i in range(m):
            for j in range(n):
                if g[i][j] == 1:
                    g[i][j] = 0
                    if count_islands(g) != 1:
                        g[i][j] = 1
                        return 1
                    g[i][j] = 1
        return 2

