class Solution:
    def minDays(self, grid):
        m, n = len(grid), len(grid[0])

        def count_islands(g):
            seen = [[False] * n for _ in range(m)]
            count = 0
            for i in range(m):
                for j in range(n):
                    if g[i][j] == 1 and not seen[i][j]:
                        count += 1
                        if count > 1:
                            return count
                        stack = [(i, j)]
                        seen[i][j] = True
                        while stack:
                            x, y = stack.pop()
                            for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                                nx, ny = x + dx, y + dy
                                if 0 <= nx < m and 0 <= ny < n and g[nx][ny] == 1 and not seen[nx][ny]:
                                    seen[nx][ny] = True
                                    stack.append((nx, ny))
            return count

        g = [row[:] for row in grid]
