var minDays = function(grid) {
    const m = grid.length, n = grid[0].length;

    function countIslands(g) {
        const seen = Array.from({ length: m }, () => new Array(n).fill(false));
        let count = 0;
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (g[i][j] === 1 && !seen[i][j]) {
                    count++;
                    if (count > 1) return count;
                    const stack = [[i, j]];
                    seen[i][j] = true;
                    while (stack.length) {
                        const [x, y] = stack.pop();
                        const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
                        for (const [dx, dy] of dirs) {
                            const nx = x + dx, ny = y + dy;
                            if (nx >= 0 && nx < m && ny >= 0 && ny < n && g[nx][ny] === 1 && !seen[nx][ny]) {
                                seen[nx][ny] = true;
                                stack.push([nx, ny]);
                            }
                        }
                    }
                }
            }
        }
        return count;
    }

    const g = grid.map(row => row.slice());
    if (countIslands(g) !== 1) return 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (g[i][j] === 1) {
                g[i][j] = 0;
                if (countIslands(g) !== 1) {
                    g[i][j] = 1;
                    return 1;
                }
                g[i][j] = 1;
            }
        }
    }
    return 2;
};
